mapper.select:
SELECT A.customer_id as customerId, C.idcard, C.`name`, B.user_id is not null as party, A.status FROM team_customer_ref A LEFT JOIN (SELECT * FROM team_user_customer_ref WHERE
user_id = #{userId}
user_id = -1
AND travel_date = #{travelDate}
) B ON A.team_id = B.team_id AND A.customer_id = B.customer_id LEFT JOIN customer C ON A.customer_id = C.customer_id WHERE A.team_id = #{teamId} AND A.status != '1' AND B.status != '1'
